import React, { useState } from 'react';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import {
  AppBar,
  Toolbar,
  Typography,
  Button,
  IconButton,
  Menu,
  MenuItem,
  Box,
  useTheme,
  useMediaQuery,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
} from '@mui/material';
import {
  Menu as MenuIcon,
  Person,
  Dashboard,
  CalendarToday,
  LocalHospital,
  People,
  Settings,
  ExitToApp,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [mobileOpen, setMobileOpen] = useState(false);
  const [anchorEl, setAnchorEl] = useState(null);

  const handleDrawerToggle = () => {
    setMobileOpen(!mobileOpen);
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const getMenuItems = () => {
    if (!user) {
      return [
        { text: 'Home', path: '/', icon: <Dashboard /> },
        { text: 'Doctors', path: '/doctors', icon: <LocalHospital /> },
        { text: 'Departments', path: '/departments', icon: <People /> },
        { text: 'Login', path: '/login', icon: <Person /> },
        { text: 'Register', path: '/register', icon: <Person /> },
      ];
    }

    const commonItems = [
      { text: 'Home', path: '/', icon: <Dashboard /> },
    ];

    switch (user.role) {
      case 'patient':
        return [
          ...commonItems,
          { text: 'Book Appointment', path: '/patient/appointments/book', icon: <CalendarToday /> },
          { text: 'My Appointments', path: '/patient/appointments', icon: <CalendarToday /> },
          { text: 'My Prescriptions', path: '/patient/prescriptions', icon: <LocalHospital /> },
        ];
      case 'doctor':
        return [
          ...commonItems,
          { text: 'Appointments', path: '/doctor/appointments', icon: <CalendarToday /> },
          { text: 'Prescriptions', path: '/doctor/prescriptions', icon: <LocalHospital /> },
        ];
      case 'admin':
        return [
          ...commonItems,
          { text: 'Users', path: '/admin/users', icon: <People /> },
          { text: 'Doctors', path: '/admin/doctors', icon: <LocalHospital /> },
          { text: 'Departments', path: '/admin/departments', icon: <People /> },
          { text: 'Appointments', path: '/admin/appointments', icon: <CalendarToday /> },
          { text: 'Prescriptions', path: '/admin/prescriptions', icon: <LocalHospital /> },
          { text: 'Statistics', path: '/admin/stats', icon: <Settings /> },
        ];
      default:
        return commonItems;
    }
  };

  const drawer = (
    <div>
      <Toolbar>
        <Typography variant="h6" noWrap component="div">
          Lumbini Nepal Hospital
        </Typography>
      </Toolbar>
      <Divider />
      <List>
        {getMenuItems().map((item) => (
          <ListItem
            button
            key={item.text}
            component={RouterLink}
            to={item.path}
            onClick={handleDrawerToggle}
          >
            <ListItemIcon>{item.icon}</ListItemIcon>
            <ListItemText primary={item.text} />
          </ListItem>
        ))}
        {user && (
          <>
            <Divider />
            <ListItem button onClick={handleLogout}>
              <ListItemIcon>
                <ExitToApp />
              </ListItemIcon>
              <ListItemText primary="Logout" />
            </ListItem>
          </>
        )}
      </List>
    </div>
  );

  return (
    <AppBar position="static">
      <Toolbar>
        {isMobile && (
          <IconButton
            color="inherit"
            aria-label="open drawer"
            edge="start"
            onClick={handleDrawerToggle}
            sx={{ mr: 2 }}
          >
            <MenuIcon />
          </IconButton>
        )}
        <Typography
          variant="h6"
          component={RouterLink}
          to="/"
          sx={{
            flexGrow: 1,
            textDecoration: 'none',
            color: 'inherit',
          }}
        >
          Lumbini Nepal Hospital
        </Typography>
        {!isMobile && (
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            {getMenuItems().map((item) => (
              <Button
                key={item.text}
                color="inherit"
                component={RouterLink}
                to={item.path}
                startIcon={item.icon}
              >
                {item.text}
              </Button>
            ))}
            {user && (
              <IconButton
                color="inherit"
                onClick={handleMenuOpen}
                sx={{ ml: 2 }}
              >
                <Person />
              </IconButton>
            )}
          </Box>
        )}
      </Toolbar>
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
      >
        <MenuItem
          component={RouterLink}
          to={`/${user?.role}/profile`}
          onClick={handleMenuClose}
        >
          Profile
        </MenuItem>
        <MenuItem onClick={handleLogout}>Logout</MenuItem>
      </Menu>
      <Drawer
        variant="temporary"
        anchor="left"
        open={mobileOpen}
        onClose={handleDrawerToggle}
        ModalProps={{
          keepMounted: true,
        }}
      >
        {drawer}
      </Drawer>
    </AppBar>
  );
};

export default Navbar;
